sql:
SELECT alert_type, threshold_value
FROM stock_alerts
WHERE user_id = 0 AND stock_id = 1 AND alert_status = 'active';

SELECT company_name
FROM stocks
WHERE stock_id = 0;

SELECT user_id, added_date
FROM stock_watchlists
WHERE stock_id = 0;

external_knowledge:
- 'Market's stars' metaphorically refers to the stocks;
- 'Bright enough to catch both the watchful eye of the analysts and the spotlight of the media' refers to stocks that are present in both the stock_watchlists and news_articles tables;
- 'Shining through their unique identifiers' means the results are grouped by and uniquely identified by stock_id.

sql:
SELECT stock_id AS name, SUM(annual_dividend) AS overall_payout
FROM stock_dividends
GROUP BY stock_id;

SELECT * FROM stock_analysis 
WHERE stock_id IN (
    SELECT stock_id FROM stock_watchlists 
    WHERE user_id = (SELECT user_id FROM users WHERE user_name = 'Bob Williams') 
      AND watchlist_name = 'Growth Stocks'
);
